package com.vidaysalud.veterinaria.veterinarioservicio.service; import com.vidaysalud.veterinaria.veterinarioservicio.dto.*;import com.vidaysalud.veterinaria.veterinarioservicio.exception.*;import com.vidaysalud.veterinaria.veterinarioservicio.model.Veterinario;import com.vidaysalud.veterinaria.veterinarioservicio.repository.VeterinarioRepository;import lombok.RequiredArgsConstructor;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;import java.util.*; @Service @RequiredArgsConstructor @Transactional public class VeterinarioService{private final VeterinarioRepository r;@Transactional(readOnly=true) public List<VeterinarioResponseDTO> listar(){return r.findAll().stream().map(this::dto).toList();}@Transactional(readOnly=true) public VeterinarioResponseDTO buscar(Integer id){return dto(get(id));}@Transactional(readOnly=true) public List<VeterinarioResponseDTO> especialidad(String e){return r.findByEspecialidadIgnoreCase(e).stream().map(this::dto).toList();}public VeterinarioResponseDTO crear(VeterinarioRequestDTO d){validar(d.getEmail(),null);return dto(r.save(map(new Veterinario(),d)));}public VeterinarioResponseDTO actualizar(Integer id,VeterinarioRequestDTO d){validar(d.getEmail(),id);return dto(r.save(map(get(id),d)));}public void eliminar(Integer id){r.delete(get(id));}private Veterinario get(Integer id){return r.findById(id).orElseThrow(()->new RecursoNoEncontradoException("Veterinario no encontrado: "+id));}private void validar(String email,Integer id){if(email!=null&&!email.isBlank())r.findByEmail(email.trim()).filter(x->!x.getIdVeterinario().equals(id)).ifPresent(x->{throw new DatoDuplicadoException("Correo de veterinario duplicado");});}private Veterinario map(Veterinario v,VeterinarioRequestDTO d){v.setNombre(d.getNombre().trim());v.setEspecialidad(d.getEspecialidad().trim());v.setTelefono(d.getTelefono());v.setEmail(d.getEmail());v.setActivo(d.getActivo()==null?true:d.getActivo());return v;}private VeterinarioResponseDTO dto(Veterinario v){return VeterinarioResponseDTO.builder().idVeterinario(v.getIdVeterinario()).nombre(v.getNombre()).especialidad(v.getEspecialidad()).telefono(v.getTelefono()).email(v.getEmail()).activo(v.getActivo()).build();}}